const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at);
const produkte = {};
for (const o of orders) {
  for (const li of (o.line_items || [])) {
    produkte[li.title] = (produkte[li.title] || 0) + li.quantity;
  }
}
const top = Object.entries(produkte).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([name]) => name);
const topText = top.length ? top.join(', ') : '(noch keine Verkaeufe - nutze die Nische als Basis)';

// Wochentag fuer Abwechslung - jeden Tag ein anderer Content-Winkel
const winkel = [
  'Social Proof & Kundenergebnisse',
  'Problem-Agitation (Schmerzpunkt der Zielgruppe dramatisieren)',
  'Behind the Scenes / Founder-Story',
  'Vorher-Nachher & Transformation',
  'Mythen aufdecken / unpopulaere Meinung',
  'Produkt-Demo mit WOW-Moment',
  'Humor / Trend-Sound-Adaption'
];
const heute = winkel[new Date().getDay()];

const prompt = 'Du bist viraler Social-Media-Stratege fuer den Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ').\n' +
  'Zielgruppe: ' + setup.ZIELGRUPPE + '\n' +
  'Bestseller aktuell: ' + topText + '\n' +
  'Content-Winkel fuer heute: ' + heute + '\n\n' +
  'Erstelle das komplette Content-Paket fuer HEUTE, auf Deutsch:\n\n' +
  '1. DREI TikTok/Reels-Hooks (erste 3 Sekunden, maximal 12 Woerter, scroll-stoppend, zum heutigen Winkel passend)\n' +
  '2. EIN komplettes 20-30s Video-Skript zum besten der 3 Hooks (Szene fuer Szene: was man sieht + was gesagt/eingeblendet wird)\n' +
  '3. EINE Instagram-Caption (Hook-Zeile, 3-4 kurze Zeilen Story, CTA, 5 passende Hashtags)\n' +
  '4. EINE Story-Idee mit Interaktions-Element (Umfrage/Slider/Frage)\n\n' +
  'Regeln: Kein generisches Marketing-Blabla, schreib wie ein Mensch, nutze Muster viraler Videos (offene Schleifen, Pattern Interrupts, direkte Ansprache). Formatiere uebersichtlich mit Emojis als Abschnittstrenner. Antworte NUR mit dem Content-Paket als Klartext (kein Markdown-Codeblock).';

return [{ json: { prompt, winkel: heute } }];

const blocks = $json.content || [];
const content = (blocks.find(b => b.type === 'text') || {}).text || '';
const winkel = $('🧠 Bestseller + Tages-Winkel').item.json.winkel;
const setup = $('⚙️ Setup').first().json;

const kopf = '🎬 CONTENT-KANONE · ' + setup.SHOP_NAME + '\n' +
  '📅 Heutiger Winkel: ' + winkel + '\n' +
  '━━━━━━━━━━━━━━━━━━\n\n';

// Telegram-Limit: 4096 Zeichen pro Nachricht -> ggf. splitten
const voll = kopf + content;
const teile = [];
for (let i = 0; i < voll.length; i += 3900) teile.push(voll.slice(i, i + 3900));
return teile.map(t => ({ json: { telegram_text: t } }));
